#include <stdio.h>

long long total_balance = 0;

void create_account(long long amount) {
    total_balance += amount;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long a, b;
        if (scanf("%lld %lld", &a, &b) != 2) break;
        total_balance = 0; // reset for this test case
        create_account(a);
        create_account(b);
        printf("%lld\n", total_balance);
    }
    return 0;
}

